  ('heelevel3-6f0ba476-moex-00162', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於遺產繼承人之敘述，何者正確？', '["繼承人若有於繼承開始後死亡或喪失繼承權者，由其直系血親卑親屬代位繼承其應繼分", "繼承人對於被繼承人有重大之虐待或侮辱情事，並經被繼承人表示其不得繼承者，其繼承權喪失", "繼承人有數人，其中一人若受監護或輔助宣告者，法院得依其他繼承人之請求，宣告該繼承人 之繼承權喪失", "同一順序之繼承人有數人時，按人數平均繼承。但非婚生子女之應繼分，為婚生子女應繼分之 二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00163', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲死亡時，留下存款新臺幣（下同）240 萬元，有配偶乙、兄丙、姊丁及妹戊為其繼承人。丁應 可繼承多少甲之遺產？', '["40萬元", "60萬元", "80萬元", "120萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00164', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於代位繼承之敘述，何者錯誤？', '["代位繼承係以自己固有之繼承權直接繼承祖父母之遺產", "代位繼承係以自己固有之繼承權繼承父或母之權利", "孫對於祖父母之遺產，有無代位繼承之資格，自應以祖父母之繼承開始為標準而決定之", "子女對父或母之遺產拋棄繼承，不能即謂對祖父母之遺產拋棄代位繼承"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
